mapper.select:
SELECT 
FROM payment_qr_config q
LEFT JOIN admin_user creator ON creator.id = q.created_by
LEFT JOIN admin_user activator ON activator.id = q.activated_by


        AND (
            q.created_at < #{cursorCreatedAt}
            OR (q.created_at = #{cursorCreatedAt} AND q.id < #{cursorId})
        )


ORDER BY q.created_at DESC, q.id DESC
LIMIT #{limit}

mapper.insert:
INSERT INTO payment_qr_config (
    name, image_path, status, created_by, activated_by, activated_at
) VALUES (
    #{name}, #{imagePath}, #{status}, #{createdBy}, #{activatedBy}, #{activatedAt}
)

mapper.update:
UPDATE payment_qr_config
SET status = 'DISABLED'
WHERE id = #{id}
